import { describe, expect, test } from 'bun:test'
import { behavioral } from '../../behavioral/behavioral.ts'
import { bThread, bSync } from '../../behavioral/behavioral.utils.ts'

describe('maxIterations factory', () => {
  test('blocks execute after 10 tool_result events', () => {
    const { bThreads, trigger, useFeedback } = behavioral()
    const events: string[] = []
    useFeedback({
      tool_result() { events.push('tool_result') },
      execute() { events.push('execute') },
      message() { events.push('message') },
    })
    bThreads.set({
      maxIterations: bThread([
        ...Array.from({ length: 10 }, () =>
          bSync({ waitFor: 'tool_result', interrupt: ['message'] }),
        ),
        bSync({
          block: 'execute',
          request: { type: 'message', detail: { content: 'Max iterations (10) reached' } },
          interrupt: ['message'],
        }),
      ]),
    })
    for (let i = 0; i < 10; i++) {
      trigger({ type: 'tool_result' })
    }
    trigger({ type: 'execute' })
    expect(events.filter(e => e === 'execute')).toHaveLength(0)
    expect(events.filter(e => e === 'message')).toHaveLength(1)
  })
})

import { describe, expect, test } from 'bun:test'
import { behavioral } from '../../behavioral/behavioral.ts'
import { bThread, bSync } from '../../behavioral/behavioral.utils.ts'

describe('dac boundary factory', () => {
  test('blocks write_file outside allowed paths', () => {
    const { bThreads, trigger, useFeedback } = behavioral()
    const executed: string[] = []
    useFeedback({
      execute(detail: { toolCall?: { name: string; arguments?: { path?: string } } }) {
        executed.push(detail?.toolCall?.arguments?.path ?? 'unknown')
      },
    })
    const allowedPaths = ['/project/src/', '/project/docs/']
    bThreads.set({
      dacBoundary: bThread([
        bSync({
          block: (e: { type: string; detail?: { toolCall?: { name: string; arguments?: { path?: string } } } }) =>
            e.type === 'execute' &&
            e.detail?.toolCall?.name === 'write_file' &&
            !allowedPaths.some(p => (e.detail?.toolCall?.arguments?.path ?? '').startsWith(p)),
        }),
      ], true),
    })
    trigger({ type: 'execute', detail: { toolCall: { name: 'write_file', arguments: { path: '/project/src/file.ts' } } } })
    expect(executed).toHaveLength(1)
    trigger({ type: 'execute', detail: { toolCall: { name: 'write_file', arguments: { path: '/etc/passwd' } } } })
    expect(executed).toHaveLength(1)
  })
})

import { describe, expect, test } from 'bun:test'
import { behavioral } from '../../behavioral/behavioral.ts'
import { bThread, bSync } from '../../behavioral/behavioral.utils.ts'

describe('batch completion factory', () => {
  test('requests invoke_inference after N completions', () => {
    const { bThreads, trigger, useFeedback } = behavioral()
    const events: string[] = []
    const isCompletion = (e: { type: string }) =>
      e.type === 'tool_result' || e.type === 'gate_rejected' || e.type === 'eval_rejected'
    useFeedback({
      invoke_inference() { events.push('invoke_inference') },
      tool_result() { events.push('tool_result') },
      gate_rejected() { events.push('gate_rejected') },
    })
    bThreads.set({
      batchCompletion: bThread([
        ...Array.from({ length: 3 }, () =>
          bSync({ waitFor: isCompletion, interrupt: ['message'] }),
        ),
        bSync({
          request: { type: 'invoke_inference' },
          interrupt: ['message'],
        }),
      ]),
    })
    trigger({ type: 'tool_result' })
    trigger({ type: 'gate_rejected' })
    expect(events.filter(e => e === 'invoke_inference')).toHaveLength(0)
    trigger({ type: 'tool_result' })
    expect(events.filter(e => e === 'invoke_inference')).toHaveLength(1)
  })

  test('zero-length batch completes immediately', () => {
    const { bThreads, trigger, useFeedback } = behavioral()
    const events: string[] = []
    useFeedback({
      invoke_inference() { events.push('invoke_inference') },
    })
    bThreads.set({
      batchCompletion: bThread([
        ...Array.from({ length: 0 }, () =>
          bSync({ waitFor: () => false, interrupt: ['message'] }),
        ),
        bSync({
          request: { type: 'invoke_inference' },
          interrupt: ['message'],
        }),
      ]),
    })
    expect(events).toContain('invoke_inference')
  })
})

import { describe, expect, test } from 'bun:test'
import { behavioral } from '../../behavioral/behavioral.ts'
import { bThread, bSync } from '../../behavioral/behavioral.utils.ts'

describe('bash safety factory', () => {
  test('blocks rm -rf /', () => {
    const { bThreads, trigger, useFeedback } = behavioral()
    const executed: string[] = []
    useFeedback({
      execute(detail: { toolCall?: { name: string; arguments?: { command?: string } } }) {
        executed.push(detail?.toolCall?.arguments?.command ?? '')
      },
    })
    const patterns = ['rm -rf /', 'dd if=', '> /dev/sda', 'mkfs.', ':(){:|:&};:']
    for (const [i, pattern] of patterns.entries()) {
      bThreads.set({
        [`bashSafety_${i}`]: bThread([
          bSync({
            block: (e: { type: string; detail?: { toolCall?: { name: string; arguments?: { command?: string } } } }) =>
              e.type === 'execute' &&
              e.detail?.toolCall?.name === 'bash' &&
              (e.detail?.toolCall?.arguments?.command ?? '').includes(pattern),
          }),
        ], true),
      })
    }
    trigger({ type: 'execute', detail: { toolCall: { name: 'bash', arguments: { command: 'ls -la' } } } })
    expect(executed).toHaveLength(1)
    trigger({ type: 'execute', detail: { toolCall: { name: 'bash', arguments: { command: 'rm -rf / --no-preserve-root' } } } })
    expect(executed).toHaveLength(1)
  })
})
